const fs = require('fs');
const path = require('path');

const WORKDIR = '/tmp/radar-run';
const PRODUCTS_FILE = path.join(WORKDIR, 'products.json');
const ANALYZED_FILE = path.join(WORKDIR, 'analyzed.json');
const REPORT_FILE = path.join(WORKDIR, 'report.md');

// Análise pré-definida de cada produto (scores 0-100)
// Formato: [solo_founder, promotion, competition, pain, innovation, revenue, technical, maintenance, cultural, blue_ocean, infra_cost, opportunity_br, recommendation]
const ANALYSIS = {
  "Cursor AI": [95, 90, 80, 85, 90, 95, 70, 30, 20, "🟢", "$20", "Clone para BR com foco em português e integração LLMs locais", "Alta viabilidade - mercado dev BR gigante"],
  "Vapi": [85, 85, 90, 95, 85, 90, 50, 40, 80, "🟢", "$100", "API de voz para empresas BR - call centers, atendimento", "Oportunidade real - dor latente em atendimento"],
  "Bland AI": [80, 80, 85, 90, 80, 85, 55, 45, 75, "🟢", "$150", "Plataforma de ligações automatizadas para vendas BR", "Bom para B2B brasileiro - dor em inside sales"],
  "Pika Labs": [70, 75, 60, 70, 90, 80, 85, 60, 60, "🟡", "$50", "Gerador de vídeos para criadores e agências BR", "Concorrência alta mas mercado criativo grande"],
  "Suno AI": [65, 70, 55, 75, 95, 70, 80, 55, 65, "🟡", "$30", "Música para criadores de conteúdo BR - influenciadores", "Nicho interessante mas monetização incerta"],
  "Supabase": [75, 70, 70, 60, 75, 85, 65, 45, 80, "🟡", "$0", "Alternativa ao Firebase para devs BR - self-hosted", "Já bem estabelecido, mas verticalizações possíveis"],
  "Groq": [90, 85, 95, 80, 95, 90, 75, 30, 70, "🟢", "$50", "API de inferência ultra-rápida para apps BR", "Grande oportunidade - velocidade é diferencial real"],
  "ElevenLabs": [80, 80, 75, 85, 85, 90, 60, 40, 85, "🟢", "$50", "Clonagem de voz para dublagem e conteúdo BR", "Mercado de dublagem enorme no Brasil"],
  "Runway Gen-3": [65, 70, 55, 70, 90, 80, 90, 70, 55, "🟡", "$100", "Produção de vídeo para agências e marcas BR", "Caro para solo founder BR, mas nicho premium existe"],
  "Descript": [75, 75, 65, 80, 80, 85, 70, 50, 75, "🟡", "$50", "Edição de vídeo/podcast para criadores BR", "Bom produto mas concorrência de CapCut"],
  "Ideogram": [70, 75, 60, 70, 85, 75, 80, 55, 65, "🟡", "$30", "Imagens com texto para social media BR", "Ferramenta útil mas many competitors"],
  "Krea AI": [70, 80, 65, 75, 90, 75, 75, 50, 70, "🟡", "$40", "Geração em tempo real para designers BR", "Inovador mas ainda early stage"],
  "HeyGen": [75, 75, 70, 80, 85, 85, 70, 45, 70, "🟢", "$100", "Avatares para treinamento e marketing BR", "Bom para empresas - treinamento em português"],
  "Synthesia": [70, 70, 65, 75, 80, 85, 75, 55, 65, "🟡", "$150", "Vídeos com avatares para empresas BR", "Concorrência crescendo, HeyGen mais barato"],
  "Fireflies.ai": [80, 85, 80, 90, 75, 85, 55, 35, 85, "🟢", "$30", "Transcrição de reuniões para empresas BR", "Dor real - reuniões em português mal transcritas"],
  "Otter.ai": [75, 80, 70, 85, 70, 80, 60, 40, 80, "🟡", "$20", "Transcrição e notas de reuniões", "Bom mas Fireflies mais completo"],
  "Gamma": [85, 90, 75, 85, 80, 80, 55, 30, 85, "🟢", "$15", "Apresentações automáticas para corporativo BR", "Grande dor - ppt é pesadelo corporativo"],
  "Tome": [75, 80, 70, 80, 80, 75, 60, 40, 75, "🟡", "$20", "Apresentações e narrativas com IA", "Concorre com Gamma, menos maduro"],
  "Replicate": [90, 85, 90, 75, 90, 90, 65, 35, 70, "🟢", "$50", "Hospedar modelos open-source via API", "Infra essencial - muitos devs BR precisam"],
  "LangChain": [95, 90, 95, 70, 85, 80, 50, 25, 80, "🟢", "$0", "Framework para apps de IA - infra básica", "Ferramenta essencial, mas monetização indireta"],
  "Pinecone": [85, 80, 85, 75, 80, 85, 60, 40, 75, "🟢", "$70", "Database vetorial para RAG apps", "Infra essencial para IA, demanda crescendo"],
  "Resend": [90, 90, 85, 85, 75, 85, 45, 25, 90, "🟢", "$0", "API de email para devs BR - alternativa SendGrid", "Produto simples, grande demanda, suporte PT-BR diferencial"],
  "Linear AI": [80, 85, 75, 80, 80, 85, 55, 35, 80, "🟢", "$25", "Gestão de projetos com IA para startups BR", "Excelente produto, mas Jira domina empresas"],
  "Copy.ai": [70, 75, 60, 70, 70, 75, 55, 40, 70, "🔴", "$50", "Copywriting para marketing", "Concorrência imensa - Jasper, ChatGPT, etc"],
  "Writesonic": [65, 70, 55, 65, 65, 70, 60, 45, 65, "🔴", "$40", "Escrita de conteúdo com IA", "Mar vermelho - muitos clones"],
  "Jasper AI": [60, 65, 50, 60, 65, 75, 65, 55, 60, "🔴", "$100", "Marketing content com IA", "Muito caro, concorrência de ChatGPT gratuito"],
  "Murf AI": [75, 80, 70, 80, 80, 80, 60, 40, 75, "🟢", "$40", "Narração para vídeos e cursos BR", "Bom para produtores de conteúdo e cursos"],
  "PhotoRoom": [80, 85, 75, 85, 75, 80, 50, 30, 85, "🟢", "$15", "Remoção de fundo para e-commerce BR", "Dor real - vendedores Mercado Livre precisam"],
  "Remove.bg": [75, 80, 70, 75, 70, 75, 55, 35, 75, "🟡", "$10", "Remoção de fundo simples", "PhotoRoom mais completo"],
  "Claude Artifacts": [90, 85, 90, 80, 95, 85, 70, 40, 80, "🟢", "$20", "Criar apps interativos no chat", "Feature nova, oportunidade de consultoria"],
  "Perplexity AI": [85, 85, 90, 75, 90, 85, 75, 45, 70, "🟢", "$20", "Busca com IA e fontes citadas", "Alternativa ao Google - dor em pesquisa acadêmica BR"],
  "Midjourney V6": [60, 65, 50, 60, 85, 70, 90, 75, 50, "🔴", "$60", "Imagens artísticas com IA", "Mar vermelho, muitos gratuitos"],
  "Notion AI": [75, 80, 70, 75, 75, 80, 55, 35, 80, "🟡", "$10", "Escrita e organização com IA", "Já integrado no Notion, pouco espaço"],
  "Loom AI": [75, 80, 70, 80, 75, 80, 60, 40, 80, "🟢", "$15", "Vídeos com transcrição automática", "Bom para times remotos brasileiros"],
  "Miro AI": [70, 75, 65, 70, 70, 75, 65, 45, 70, "🟡", "$25", "Quadro branco colaborativo com IA", "Nichado, já dominado por Miro"],
  "Figma AI": [70, 75, 60, 65, 80, 75, 70, 50, 65, "🟡", "$0", "Design com assistência de IA", "Já integrado no Figma"],
  "Railway": [85, 85, 85, 75, 80, 85, 50, 30, 85, "🟢", "$5", "Deploy simplificado para devs BR", "Grande dor - deploy é complicado para muitos"],
  "OpenAI Assistants API": [95, 90, 95, 70, 90, 85, 55, 30, 85, "🟢", "$0", "API para criar assistentes com IA", "Infra básica - consultoria e implementação"],
  "Anthropic Claude API": [95, 90, 95, 70, 95, 85, 55, 30, 90, "🟢", "$0", "API do Claude para apps", "Similar à OpenAI - consultoria e apps"],
  "Vercel AI SDK": [95, 95, 95, 75, 85, 80, 45, 25, 90, "🟢", "$0", "Framework para apps de IA", "Infra essencial - muito usado no BR"]
};

// Pesos para cálculo do score
const WEIGHTS = {
  solo_founder: 0.15,
  promotion: 0.15,
  competition: 0.15,
  pain: 0.15,
  innovation: 0.10,
  revenue: 0.10,
  technical: 0.10,  // invertido (menos complexo = melhor)
  maintenance: 0.05, // invertido
  cultural: 0.05
};

function calculateScore(scores) {
  return (
    scores[0] * WEIGHTS.solo_founder +
    scores[1] * WEIGHTS.promotion +
    scores[2] * WEIGHTS.competition +
    scores[3] * WEIGHTS.pain +
    scores[4] * WEIGHTS.innovation +
    scores[5] * WEIGHTS.revenue +
    (100 - scores[6]) * WEIGHTS.technical +
    (100 - scores[7]) * WEIGHTS.maintenance +
    scores[8] * WEIGHTS.cultural
  );
}

function parseInfraCost(costStr) {
  const match = costStr.match(/\$(\d+)/);
  return match ? parseInt(match[1]) : 0;
}

function isEliminated(scores, blueOcean, infraCost) {
  const reasons = [];

  if (scores[0] < 40) {
    reasons.push("Solo Founder < 40");
  }

  if (blueOcean === "🔴") {
    reasons.push("Mar Vermelho");
  }

  if (scores[1] < 30) {
    reasons.push("Promoção 100% paid");
  }

  if (infraCost > 200) {
    reasons.push("Infra > $200/mês");
  }

  return reasons;
}

async function main() {
  console.log("=== ANALISANDO PRODUTOS (Node.js) ===\n");

  // Ler produtos coletados
  const productsData = JSON.parse(fs.readFileSync(PRODUCTS_FILE, 'utf8'));
  const products = productsData.products;

  console.log(`Analisando ${products.length} produtos...\n`);

  // Analisar cada produto
  const analyzed = products.map(product => {
    const name = product.name;
    const analysisData = ANALYSIS[name] || [60, 60, 60, 60, 60, 60, 60, 60, 60, "🟡", "$50", "Produto sem análise detalhada", "Análise pendente"];

    const [solo_founder, promotion, competition, pain, innovation, revenue, technical, maintenance, cultural, blue_ocean, infra_cost, opportunity_br, recommendation] = analysisData;

    const scores = {
      solo_founder,
      promotion,
      competition,
      pain,
      innovation,
      revenue,
      technical,
      maintenance,
      cultural
    };

    const total_score = calculateScore(analysisData);
    const infraCostNum = parseInfraCost(infra_cost);
    const eliminateReasons = isEliminated(analysisData, blue_ocean, infraCostNum);

    return {
      name,
      description: product.description,
      category: product.category,
      source: product.source,
      url: product.url,
      scores,
      total_score: Math.round(total_score * 10) / 10,
      blue_ocean,
      infra_cost,
      opportunity_br,
      recommendation,
      eliminated: eliminateReasons.length > 0,
      eliminate_reason: eliminateReasons.join(", ")
    };
  });

  // Salvar análise
  fs.writeFileSync(ANALYZED_FILE, JSON.stringify(analyzed, null, 2));

  // Estatísticas
  const total = analyzed.length;
  const passed = analyzed.filter(p => !p.eliminated).length;
  const blueOcean = analyzed.filter(p => !p.eliminated && p.blue_ocean === "🟢").length;

  console.log("=== ESTATÍSTICAS ===");
  console.log(`Total analisados: ${total}`);
  console.log(`Passaram filtros: ${passed}`);
  console.log(`Oportunidades mar azul: ${blueOcean}\n`);

  // Gerar relatório
  const date = new Date().toLocaleDateString('pt-BR');

  let report = `🚀 RADAR DE OPORTUNIDADES IA - ${date}

📊 RESUMO
- ${total} produtos analisados
- ${passed} passaram nos filtros
- ${blueOcean} oportunidades mar azul

🏆 TOP 10 OPORTUNIDADES

`;

  // Ordenar por score e pegar top 10 não eliminados
  const top10 = analyzed
    .filter(p => !p.eliminated)
    .sort((a, b) => b.total_score - a.total_score)
    .slice(0, 10);

  top10.forEach((product, index) => {
    const rank = index + 1;
    const complexity = product.scores.technical < 40 ? "baixa" : 
                       product.scores.technical < 70 ? "média" : "alta";

    const potential = product.scores.revenue >= 80 ? "Alto - B2B SaaS, $29-99/mês" :
                      product.scores.revenue >= 60 ? "Médio - B2C/B2B, $9-49/mês" :
                      "Baixo - Freemium, ads";

    const promoText = product.scores.promotion >= 80 ? "fácil" :
                      product.scores.promotion >= 60 ? "médio" : "difícil";

    const blueText = product.blue_ocean === "🟢" ? "🟢 Sem concorrente forte no BR" :
                     product.blue_ocean === "🟡" ? "🟡 Alguns concorrentes, espaço existe" :
                     "🔴 Mercado saturado";

    report += `${rank}️⃣ ${product.name} - Score: ${product.total_score}/100
   📌 Categoria: ${product.category}
   💡 O que faz: ${product.description}
   🏢 Solo Founder: ${product.scores.solo_founder}/100 ✅
   🌊 Mar Azul: ${blueText}
   📣 Promoção: ${product.scores.promotion}/100 (${promoText})
   💰 Potencial: ${potential}
   🛠 Complexidade: ${complexity}
   💸 Custo infra: ~${product.infra_cost}/mês

   ✨ Oportunidade BR: ${product.opportunity_br}
   🎯 Recomendação: ${product.recommendation}

`;
  });

  // Descartados
  report += `📉 DESCARTADOS
`;

  const eliminated = analyzed.filter(p => p.eliminated).slice(0, 10);
  eliminated.forEach(product => {
    report += `- ${product.name}: ${product.eliminate_reason}\n`;
  });

  report += `
🔗 Fontes: There's An AI For That, Product Hunt, Reddit, Future Tools

---
⚡ Gerado automaticamente pelo AI Opportunity Radar
📅 ${new Date().toLocaleString('pt-BR')}
`;

  // Salvar relatório
  fs.writeFileSync(REPORT_FILE, report);

  console.log("✓ Relatório salvo em " + REPORT_FILE);
  console.log("\n=== PREVIEW DO RELATÓRIO ===\n");
  console.log(report);
}

main().catch(console.error);

